25	const COMPONENT_TYPES = new Set(["rune"]);
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	const FIRST_INSURANCE_SURCHARGE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
33	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
34	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
35	
36	// Components are priced in blocks: a block of exactly BLOCK_SIZE alike components
37	// costs BLOCK_PREMIUM; leftover components are priced individually.
38	const componentBasePremium = (count: number, perComponent: number): number => {
39	  const blocks = Math.floor(count / BLOCK_SIZE);
40	  const remainder = count % BLOCK_SIZE;
41	  return blocks * BLOCK_PREMIUM + remainder * perComponent;
42	};
43	
44	const itemsBasePremium = (items: Item[]): number => {
45	  let total = 0;
46	  const componentCounts: Record<string, number> = {};
47	  for (const item of items) {
48	    if (COMPONENT_TYPES.has(item.type)) {
49	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
50	    } else {
51	      total += BASE_PREMIUM[item.type];
52	    }
53	  }
54	  for (const type of Object.keys(componentCounts)) {
55	    total += componentBasePremium(componentCounts[type], BASE_PREMIUM[type]);
56	  }
57	  return total;
58	};
59	
60	const quotePremium = (items: Item[]): number => {
61	  const itemsPremium = itemsBasePremium(items) * (1 + FIRST_INSURANCE_SURCHARGE);
62	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
63	};
64	
65	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
66	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
67	  return { results };
68	};
